/**
 * Theme JavaScript
 *
 * Handles mobile menu toggle and other theme interactions
 *
 * @package Videohub360_Theme
 * @since 1.0.0
 */

(function() {
    'use strict';

    /**
     * Mobile menu toggle
     */
    function initMobileMenu() {
        var menuToggle = document.querySelector('.menu-toggle');
        var navigation = document.querySelector('.main-navigation');

        if (!menuToggle || !navigation) {
            return;
        }

        menuToggle.addEventListener('click', function() {
            navigation.classList.toggle('toggled');
            var expanded = menuToggle.getAttribute('aria-expanded') === 'true';
            menuToggle.setAttribute('aria-expanded', !expanded);
        });

        // Close menu when clicking outside
        document.addEventListener('click', function(event) {
            var isClickInside = navigation.contains(event.target) || menuToggle.contains(event.target);

            if (!isClickInside && navigation.classList.contains('toggled')) {
                navigation.classList.remove('toggled');
                menuToggle.setAttribute('aria-expanded', 'false');
            }
        });

        // Close menu on escape key
        document.addEventListener('keydown', function(event) {
            if (event.key === 'Escape' && navigation.classList.contains('toggled')) {
                navigation.classList.remove('toggled');
                menuToggle.setAttribute('aria-expanded', 'false');
                menuToggle.focus();
            }
        });
    }

    /**
     * Smooth scroll for anchor links
     */
    function initSmoothScroll() {
        var links = document.querySelectorAll('a[href^="#"]');

        links.forEach(function(link) {
            link.addEventListener('click', function(e) {
                var href = this.getAttribute('href');

                if (href === '#') {
                    return;
                }

                var target = document.querySelector(href);

                if (target) {
                    e.preventDefault();
                    target.scrollIntoView({
                        behavior: 'smooth',
                        block: 'start'
                    });
                }
            });
        });
    }

    /**
     * Add loaded class to body for CSS transitions
     */
    function addLoadedClass() {
        document.body.classList.add('page-loaded');
    }

    /**
     * Lazy load images
     */
    function initLazyLoad() {
        if ('IntersectionObserver' in window) {
            var lazyImages = document.querySelectorAll('img[loading="lazy"]');

            var imageObserver = new IntersectionObserver(function(entries) {
                entries.forEach(function(entry) {
                    if (entry.isIntersecting) {
                        var image = entry.target;
                        image.src = image.dataset.src || image.src;
                        image.classList.add('loaded');
                        imageObserver.unobserve(image);
                    }
                });
            });

            lazyImages.forEach(function(image) {
                imageObserver.observe(image);
            });
        }
    }

    /**
     * Apply custom badge colors from data attributes
     */
    function applyBadgeColors() {
        var badges = document.querySelectorAll('.live-badge[data-badge-color]');
        badges.forEach(function(badge) {
            var color = badge.getAttribute('data-badge-color');
            if (color) {
                badge.style.setProperty('--badge-color', color);
                badge.style.backgroundColor = color;
            }
        });
    }

    /**
     * Initialize all theme functionality
     */
    function init() {
        initMobileMenu();
        initSmoothScroll();
        addLoadedClass();
        initLazyLoad();
        applyBadgeColors();
    }

    // Run on DOM ready
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

})();
